SELECT id, path, name, city FROM stores WHERE city='Brno' AND name LIKE '%Veveri%';

SELECT sku, path, brand, series, model, name FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='HECO 3DW-64B' AND name='Nut Bolt and Washer' AND json_extract(properties,'$.fastener_type')='bolt' AND json_extract(properties,'$.diameter')='10 mm' LIMIT 5;
SELECT sku, path, brand, series, model, name FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='TopFix GTU-YPJ' AND name='Wood and Drywall Screw' AND json_extract(properties,'$.screw_type')='wood screw' AND json_extract(properties,'$.diameter')='3 mm' LIMIT 5;
SELECT sku, path, brand, series, model, name FROM products WHERE brand='Ajax' AND series='Ajax Eco Classic' AND model='25C-DXE' AND name='Cleaning Liquid' AND json_extract(properties,'$.cleaner_type')='degreaser' LIMIT 5;
SELECT sku, path, brand, series, model, name FROM products WHERE brand='Ajax' AND series='Ajax Eco Classic' AND model='25C-DXE' AND name='Cleaning Liquid' AND json_extract(properties,'$.cleaner_type')='floor cleaner' LIMIT 5;
SELECT sku, path, brand, series, model, name FROM products WHERE brand='Heco' AND series='Heco Zinc Plated' AND model='HECO 3DW-64B' AND name='Nut Bolt and Washer' AND json_extract(properties,'$.fastener_type')='bolt' AND json_extract(properties,'$.diameter')='8 mm' LIMIT 5;
SELECT sku, path, brand, series, model, name FROM products WHERE brand='Festool' AND series='Festool Stackable' AND model='SYS 3JJ-9LM' AND name='Tool Box and Bag' AND json_extract(properties,'$.storage_type')='tool bag' LIMIT 5;

SELECT id, path, name, city FROM stores WHERE city='Brno' ORDER BY name LIMIT 20;

SELECT sku, path, brand, series, model, name, json_extract(properties,'$.fastener_type') AS fastener_type, json_extract(properties,'$.diameter') AS diameter FROM products WHERE brand='Heco' AND model='HECO 3DW-64B' LIMIT 20;
SELECT sku, path, brand, series, model, name, json_extract(properties,'$.screw_type') AS screw_type, json_extract(properties,'$.diameter') AS diameter FROM products WHERE brand='Heco' AND model='TopFix GTU-YPJ' LIMIT 20;
SELECT sku, path, brand, series, model, name, json_extract(properties,'$.cleaner_type') AS cleaner_type FROM products WHERE brand='Ajax' AND model='25C-DXE' LIMIT 20;
SELECT sku, path, brand, series, model, name, json_extract(properties,'$.storage_type') AS storage_type FROM products WHERE brand='Festool' AND model='SYS 3JJ-9LM' LIMIT 20;
